							m.modifier.source_id = this.id
							m.modifier.target_id = t.id

							queue_insert(store, m)
						end
					end

					U.y_animation_wait(this)

					a.ts = store.tick_ts
				end
			end

			if not SU.y_enemy_walk_until_blocked(store, this, false, function(this, store)
