function scripts.enemy_unblinded_abomination_stage_8.update(this, store)
	local nodes = P:nearest_nodes(this.pos.x, this.pos.y, nil, nil, false)
	local pi, spi, ni = unpack(nodes[1])
	local last_idle = store.tick_ts
