			U.y_animation_play(this, "light_on", nil, store.tick_ts)

			is_on = true
		elseif this.turn_off then
			this.turn_off = nil

			U.y_animation_play(this, "light_off", nil, store.tick_ts)

			is_on = false
		end

		if is_on then
			U.animation_start(this, "idle_on", nil, store.tick_ts, true)
