			end

			local cont, blocker, ranged = SU.y_enemy_walk_until_blocked(store, this)

			if not cont then
			-- block empty
			else
				if blocker then
					if p_sys_a then
						p_sys_a.particle_system.emit = false
					end

					if p_sys_b then
						p_sys_b.particle_system.emit = false
					end

					if not SU.y_wait_for_blocker(store, this, blocker) then
