							goto label_319_0
						end

						coroutine.yield()
					end
				elseif ranged then
					if p_sys_a then
						p_sys_a.particle_system.emit = false
					end

					if p_sys_b then
						p_sys_b.particle_system.emit = false
					end

					while SU.can_range_soldier(store, this, ranged) and #this.enemy.blockers == 0 do
						if not SU.y_enemy_range_attacks(store, this, ranged) then
