		if not target and this.holder_id then
			for _, e in pairs(store.entities) do
				if e.tower and e.tower.holder_id == this.holder_id then
					target = e

					break
				end
			end
		end
	end

	while true do
		find_target()

		if not target then
			break
		end

		local pos_diff = V.v(target.pos.x - this.pos.x, target.pos.y - this.pos.y)
		local n_x, n_y = V.normalize(pos_diff.x, pos_diff.y)

		this.pos.x = this.pos.x + n_x * this.speed * store.tick_length
		this.pos.y = this.pos.y + n_y * this.speed * store.tick_length

		if V.dist(this.pos.x, this.pos.y, target.pos.x, target.pos.y) < 10 then
			if this.holder_id and not target.tower.can_be_mod then
				break
			end

			local mod = E:create_entity(this.mod)

			mod.modifier.target_id = target.id

			queue_insert(store, mod)

			break
		end

		if next_decal_ts <= store.tick_ts then
			next_decal_ts = store.tick_ts + fts(10)

			local decal = E:create_entity(this.decal)

			decal.pos = V.vclone(this.pos)

			queue_insert(store, decal)
		end

		coroutine.yield()
	end

	queue_remove(store, this)
end

scripts.mod_mage_treasure = {}
function scripts.mod_mage_treasure.insert(this, store)
	local target = store.entities[this.modifier.target_id]
	if not target then
		return false
	end
	if not target._mage_treasure_extra_gold then
		target._mage_treasure_extra_gold = 0
		target._mage_treasure_extra_gold_step = math.ceil(this.extra_gold_factor * target.enemy.gold)
		target._mage_treasure_extra_gold_max = math.ceil(this.max_extra_gold_factor * target.enemy.gold)
	end

	if target._mage_treasure_extra_gold >= target._mage_treasure_extra_gold_max then
		return false
	end

	target._mage_treasure_extra_gold = target._mage_treasure_extra_gold + target._mage_treasure_extra_gold_step
	target.enemy.gold = target.enemy.gold + target._mage_treasure_extra_gold_step

	return false
end

return scripts
